                    return JsonSerializer.Deserialize<CostsResult>(json, Options);
                case "organization.usage.audio_speeches.result":
                    return JsonSerializer.Deserialize<UsageAudioSpeechesResult>(json, Options);
                case "organization.usage.audio_transcriptions.result":
                    return JsonSerializer.Deserialize<UsageAudioTranscriptionsResult>(json, Options);
