public sealed class CreateImageRequest
{
    /// <summary>A text description of the desired image(s). The maximum length is 32000 characters for the GPT image models, 1000 characters for `dall-e-2` and 4000 characters for `dall-e-3`.</summary>
    [JsonPropertyName("prompt")]
