    /// <summary>The model to use for image generation. One of `dall-e-2`, `dall-e-3`, or a GPT image model (`gpt-image-1`, `gpt-image-1-mini`, `gpt-image-1.5`). Defaults to `dall-e-2` unless a parameter specific to the GPT image models is used.</summary>
    [JsonPropertyName("model")]
    public object? Model { get; set; }

    /// <summary>The number of images to generate. Must be between 1 and 10. For `dall-e-3`, only `n=1` is supported.</summary>
    [JsonPropertyName("n")]
    public long? N { get; set; }

    /// <summary>
    /// The quality of the image that will be generated.
    /// - `auto` (default value) will automatically select the best quality for the given model.
    /// - `high`, `medium` and `low` are supported for the GPT image models.
    /// - `hd` and `standard` are supported for `dall-e-3`.
    /// - `standard` is the only option for `dall-e-2`.
    /// </summary>
    [JsonPropertyName("quality")]
    public CreateImageRequestQuality? Quality { get; set; }

    /// <summary>The format in which generated images with `dall-e-2` and `dall-e-3` are returned. Must be one of `url` or `b64_json`. URLs are only valid for 60 minutes after the image has been generated. This parameter isn't supported for the GPT image models, which always return base64-encoded images.</summary>
    [JsonPropertyName("response_format")]
    public CreateImageRequestResponseFormat? ResponseFormat { get; set; }

    /// <summary>The format in which the generated images are returned. This parameter is only supported for the GPT image models. Must be one of `png`, `jpeg`, or `webp`.</summary>
    [JsonPropertyName("output_format")]
    public CreateImageRequestOutputFormat? OutputFormat { get; set; }

    /// <summary>The compression level (0-100%) for the generated images. This parameter is only supported for the GPT image models with the `webp` or `jpeg` output formats, and defaults to 100.</summary>
    [JsonPropertyName("output_compression")]
    public long? OutputCompression { get; set; }

    /// <summary>
    /// Generate the image in streaming mode. Defaults to `false`. See the
    /// [Image generation guide](/docs/guides/image-generation) for more information.
    /// This parameter is only supported for the GPT image models.
    /// </summary>
    [JsonPropertyName("stream")]
    public bool? Stream { get; set; }

