/// <summary>Decodes a ItemResource from JSON by its "type" discriminator, returning the raw JSON element when the value is unknown.</summary>
internal static class ItemResourceUnion
{
    private static readonly JsonSerializerOptions Options = new() { PropertyNameCaseInsensitive = true };

    public static object? Decode(string json)
    {
        if (string.IsNullOrEmpty(json))
        {
            return null;
        }
        using JsonDocument document = JsonDocument.Parse(json);
        JsonElement root = document.RootElement;
        if (root.ValueKind == JsonValueKind.Object &&
            root.TryGetProperty("type", out JsonElement discriminator) &&
            discriminator.ValueKind == JsonValueKind.String)
        {
            switch (discriminator.GetString())
            {
                case "apply_patch_call":
                    return JsonSerializer.Deserialize<ApplyPatchToolCall>(json, Options);
                case "apply_patch_call_output":
                    return JsonSerializer.Deserialize<ApplyPatchToolCallOutput>(json, Options);
                case "code_interpreter_call":
                    return JsonSerializer.Deserialize<CodeInterpreterToolCall>(json, Options);
                case "compaction":
                    return JsonSerializer.Deserialize<CompactionBody>(json, Options);
                case "computer_call":
                    return JsonSerializer.Deserialize<ComputerToolCall>(json, Options);
                case "computer_call_output":
                    return JsonSerializer.Deserialize<ComputerToolCallOutputResource>(json, Options);
                case "custom_tool_call":
                    return JsonSerializer.Deserialize<CustomToolCallResource>(json, Options);
                case "custom_tool_call_output":
                    return JsonSerializer.Deserialize<CustomToolCallOutputResource>(json, Options);
                case "file_search_call":
                    return JsonSerializer.Deserialize<FileSearchToolCall>(json, Options);
                case "function_call":
                    return JsonSerializer.Deserialize<FunctionToolCallResource>(json, Options);
                case "function_call_output":
                    return JsonSerializer.Deserialize<FunctionToolCallOutputResource>(json, Options);
                case "image_generation_call":
                    return JsonSerializer.Deserialize<ImageGenToolCall>(json, Options);
                case "local_shell_call":
                    return JsonSerializer.Deserialize<LocalShellToolCall>(json, Options);
                case "local_shell_call_output":
                    return JsonSerializer.Deserialize<LocalShellToolCallOutput>(json, Options);
                case "mcp_approval_request":
                    return JsonSerializer.Deserialize<McpApprovalRequest>(json, Options);
                case "mcp_approval_response":
                    return JsonSerializer.Deserialize<McpApprovalResponseResource>(json, Options);
                case "mcp_call":
                    return JsonSerializer.Deserialize<McpToolCall>(json, Options);
                case "mcp_list_tools":
                    return JsonSerializer.Deserialize<McpListTools>(json, Options);
                case "message":
                    return JsonSerializer.Deserialize<OutputMessage>(json, Options);
                case "reasoning":
                    return JsonSerializer.Deserialize<ReasoningItem>(json, Options);
                case "shell_call":
                    return JsonSerializer.Deserialize<FunctionShellCall>(json, Options);
                case "shell_call_output":
                    return JsonSerializer.Deserialize<FunctionShellCallOutput>(json, Options);
                case "tool_search_call":
                    return JsonSerializer.Deserialize<ToolSearchCall>(json, Options);
                case "tool_search_output":
                    return JsonSerializer.Deserialize<ToolSearchOutput>(json, Options);
                case "web_search_call":
                    return JsonSerializer.Deserialize<WebSearchToolCall>(json, Options);
            }
        }
        return JsonSerializer.Deserialize<JsonElement>(json, Options);
    }
}

